/**
 * Types for the various interactive analyses.
 *
 * @since 5.0
 */
import type { AnalysisView2DUnion } from "../2d/analysis/types.js";
import type { AnalysisView3DUnion } from "../3d/analysis/types.js";

/**
 * Union of all possible analysis views that can be added to a [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/) or
 * [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/).
 *
 * @since 5.0
 */
export type AnalysisViewUnion = AnalysisView2DUnion | AnalysisView3DUnion;

/**
 * Describes how measurements are computed for analysis tools.
 *
 * @since 5.0
 */
export type MeasurementMode = "euclidean" | "geodesic";